var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"지진도, 마물들이 마을에 계속 나타나는 것도 이상했어. 뭔가 이상했다고!","JPN":"地震も、魔物どもが村に現れるようになったのも、なにか怪しいと思っていた。やっぱりそうだったんだ！","ENG":"The earthquakes and monsters invading the village. I know something was off!","TWN":"地震也好，不斷出現在村子裡的怪物也好，都很不尋常。一定有什麼不對勁！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"어쩐지 최근 들어 안 좋은 징조가 너무 많았어요! 결국 종말의 예언처럼 세상이 끝나려는 거라고요!","JPN":"最近は不穏な出来事が多すぎたわ！　まるで終末の予言通り、世界が終わろうとしているかのように！","ENG":"No wonder there were so many omens recently! The world is going to end just like it said in the Apocalypse Augury!","TWN":"難怪最近怪事這麼多！是末日的預言要成真了嗎！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"다들 시끄러워! 불길한 소리 좀 그만해!","JPN":"みんな黙って！　不安を煽るのはやめなさい！","ENG":"Everyone, quiet! Enough with the doom talk!","TWN":"大家安靜！別再說這些不吉利的話！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"하지만 아가씨도 보셨잖아요. 그건 틀림없는 반역자의 낙인이었어요.","JPN":"お嬢様も見ましたよね。あれは間違いなく反逆者の烙印でしたよ。","ENG":"But you saw it too, Miss Morgana. It was no doubt the brand of the traitor.","TWN":"但小姐也有看到吧？那確實是叛徒的烙印。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"반역자 때문에 종말이 올 겁니다!","JPN":"反逆者が終末をもたらすぞ！","ENG":"The end will come because of the traitor!","TWN":"因為叛徒，末日將會到來！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"동토의 외지인을 데려오면서 낙인을 확인하지 않다니…! 제사장께서 실수라도 하신 걸까요?","JPN":"凍土からよそ者を連れてくるときに烙印を確認しなかったなんて……！　司祭長はうっかり間違えたんでしょうか？","ENG":"Letting an outsider from the gelid lands in here without even checking if she had the mark...! Did the High Priest make a mistake?","TWN":"從凍土來的外地人卻沒有確認烙印…！祭司長也會犯錯嗎？！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린이…?","JPN":"マーリンが……？","ENG":"Merlin making a mistake...?","TWN":"梅林…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HEALER_ROOT_NPC_NULL","text":{"KOREA":"제사장님… 정말 괜찮을까요…?","JPN":"司祭長、本当に大丈夫なんですか？","ENG":"Ma'am... are you sure...?","TWN":"祭司長…真的沒關係嗎…？"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"대신 오늘 본 것들은 전부 비밀로 해주렴. 그래줄 수 있지?","JPN":"その代わり今日ここで見たものは、全て内緒にしてもらえるかしら？　お願い。","ENG":"In return, please keep what you saw today a secret, okay?","TWN":"但今天的事你必須保密，可以嗎？"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"사람들이 불안해하고 있습니다.","JPN":"みんなが不安になっています。","ENG":"The people are worrying.","TWN":"大家都很不安。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"뭐라고 말이라도 해주세요, 모르가나 아가씨.","JPN":"何か言ってください、モルガナお嬢様。","ENG":"You should go out there and reassure them, Miss Morgana.","TWN":"請說點什麼吧，莫甘娜小姐。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 멀린을 만나서 얘기해볼게.","JPN":"あたしがマーリンに会って話してみる。","ENG":"I'll go talk to Merlin.","TWN":"我去找梅林談談。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그전까지 루를 찾지도, 건들지도 마! 알겠지?","JPN":"それまではルーを探したり、手を出したりはしないで！　わかった？","ENG":"Until then, don't go looking for or even touch Lugh! Okay?!","TWN":"在那之前，不要去找露，更不准碰她！明白嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하아… 하…","JPN":"はあ……はぁ……","ENG":"*Huff* *Huff*","TWN":"呼呼…呼…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"바보 같이 방심했어요. 그런 식으로 들켜선 안 됐는데…","JPN":"情けない。あんなバレ方……油断してしまった。","ENG":"I was a fool to let my guard down. I shouldn't have been caught like that...","TWN":"還是…還是大意了嗎？不應該那樣被發現的…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이런 순간에도 제 생각만 하다니.","JPN":"こんな時にも自分のことしか考えないなんて。","ENG":"Even now, I'm just thinking about myself.","TWN":"在這種時候還只想著自己。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저란 사람은 참 이기적이네요.","JPN":"私という人間はなんて自分勝手なのでしょう。","ENG":"I am such a selfish person.","TWN":"我真是個自私的人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그때 모르가나의 표정… 무척 당황한 것 같았죠.","JPN":"あの時のモルガナの顔……すごく狼狽していたと思います。","ENG":"Morgana's expression... She seemed extremely flustered.","TWN":"那時候莫甘娜的表情…看起來非常驚慌。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"자길 속였다고 생각할 거예요. 낙인에 대해 말할 기회가 있었는데도, 말하지 않았으니까.","JPN":"自分は騙されたと思っているでしょう。烙印について話す機会があったのに、言わなかったのだから。","ENG":"I'm sure she's thinking that I fooled her. Because even though I had a chance to tell her about the mark, I didn't.","TWN":"一定是覺得我欺騙了她…明明有機會和她說明的…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그 망설임의 대가를 치르는 거네요.","JPN":"その躊躇いの代償が今返ってきたんです。","ENG":"Guess I'm paying for my hesitation.","TWN":"這就是猶豫的後果。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그때처럼…","JPN":"あの時のように……","ENG":"Just like that time…","TWN":"就像以前一樣…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 낙인이 있는 한… 결국 이렇게 될 운명인 거겠죠.","JPN":"この烙印がある限り……私はこうなる運命なんですね。","ENG":"As long as I have this mark... it was fated to become this eventually.","TWN":"只要有這個烙印…結果還是會變成這樣。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};